parameters.text:
=Generate an article using the following settings:

Mode: {{$json.mode}}
Keyword: {{$json.keyword}}
Category: {{$json.category}}
Tone: {{$json.tone}}
Length: {{$json.length}}
  Target Language:{{ $json.language }}

IMPORTANT:
- Follow all instructions strictly
- Output must be valid JSON only

parameters.jsCode:
// Get full input safely
const item = $input.first().json;

// Try all possible fields
let raw =
  item.output ||
  item.text ||
  item.data ||
  item;

// If it's a string → parse it
let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  return [{
    json: {
      success: false,
      error: "Failed to parse AI output",
      rawOutput: raw
    }
  }];
}

// Return clean structured data
return [{
  json: {
    title: parsed.title || "",
    content: parsed.content || "",
    imagePrompt: parsed.imagePrompt || "",
    imageSearch: parsed.imageSearch || ""
  }
}];

const prompt = $input.first().json.text;

return [{
  json: {
    ...$json,
    imagePromptEnhanced: prompt.trim()
  }
}];

const input = $input.first().json || {};
const body = input.body || {};

// 🌍 Normalize language → output as "arabic" or "english"
let language = (input.language || body.language || body.lang || "english").toLowerCase();

if (["ar", "arabic"].includes(language)) {
  language = "arabic";
} else {
  language = "english";
}

// 🧠 Detect keyword (from all possible sources)
const keyword =
  input.keyword ||        // already processed (category → keyword)
  input.text ||           // from LLM node
  body.keyword ||         // from frontend keyword mode
  "";

// 🧠 Detect category
const category =
  input.category ||
  body.category ||
  "";

// ✅ Smart mode detection
let mode = "keyword";

if (!keyword && category) {
  mode = "category";
}

// Final output
return [{
  json: {
    mode,
    keyword: keyword || category || "General Topic",
    category,
    tone: input.tone || body.tone || "formal",
    length: input.length || body.length || "medium",
    language
  }
}];

parameters.text:
=Generate an article using the following settings:


Keyword: {{$json.keyword}}
Category: {{$json.category}}
Tone: {{$json.tone}}
Length: {{$json.length}}
Target Language:{{ $json.language }}

IMPORTANT:
- Follow all instructions strictly
- Output must be valid JSON only

parameters.jsCode:
// Parse the JSON string returned in the "text" field
const llmOutput = $json["text"]; // your LLM node field
let parsedOutput = [];

try {
  parsedOutput = JSON.parse(llmOutput); // convert string to real JSON
} catch (err) {
  throw new Error("Failed to parse LLM JSON output: " + err.message);
}

return parsedOutput.map(item => ({ json: item }));
